{{state_descriptions}}: {{
  "vital_signs": "Current physiological indicators including heart_rate, blood_pressure (systolic/diastolic), and oxygen_saturation.",
  "biomarker_levels": "Internal laboratory values relevant to the condition (e.g., blood glucose, creatinine, white blood cell count).",
  "active_medications": "A list of medications currently circulating in the patient's system and their remaining effective duration.",
  "disease_progression_index": "A hidden numerical value (0.0 to 1.0) representing the underlying severity or stage of the primary condition.",
  "cumulative_toxicity": "A measure of side-effect accumulation or organ stress from the sequence of treatments.",
  "treatment_history": "A chronological log of all actions executed by the agent and the patient's historical response markers."
}}
{action_set_definitions}: {
  "get_patient_state": {
    "description": "Retrieves the current clinical state of the patient including vitals, lab results, and medication list. Use this to assess surgical candidacy and systemic stability.",
    "parameters": {
      "type": "object",
      "properties": {
        "requested_fields": {
          "type": "array",
          "items": {
            "type": "string",
            "enum": [
              "vital_signs",
              "biomarker_levels",
              "active_medications",
              "cumulative_toxicity",
              "treatment_history"
            ]
          }
        }
      },
      "required": [
        "requested_fields"
      ]
    },
    "example_output": {
      "vital_signs": {
        "bp": "120/80",
        "hr": 72
      },
      "biomarker_levels": {
        "anc": 1.5,
        "platelets": 200,
        "wbc": 4.0
      }
    }
  },
  "advance_time": {
    "description": "Advances the environment clock by a specified number of days. This tool simulates the passage of time, allowing for healing or recovery from chemotherapy toxicity. It returns the updated state after the duration.",
    "parameters": {
      "type": "object",
      "properties": {
        "days": {
          "type": "integer",
          "description": "Number of days to wait."
        }
      },
      "required": [
        "days"
      ]
    },
    "example_output": {
      "new_state": "Object containing updated vitals and biomarkers after the wait.",
      "days_remaining_until_deadline": 9
    }
  },
  "consult_oncology": {
    "description": "Coordinates with the oncology team to get clearance for invasive dental procedures based on current systemic labs.",
    "parameters": {
      "type": "object",
      "properties": {
        "procedure_proposed": {
          "type": "string"
        },
        "patient_lab_summary": {
          "type": "object"
        }
      },
      "required": [
        "procedure_proposed",
        "patient_lab_summary"
      ]
    },
    "example_output": {
      "clearance": "approved",
      "conditions": "prophylactic antibiotics required"
    }
  },
  "perform_dental_procedure": {
    "description": "Executes a dental intervention. For high-risk patients, mandatory surgical protocols (like primary closure) must be specified.",
    "parameters": {
      "type": "object",
      "properties": {
        "tooth_number": {
          "type": "string"
        },
        "action": {
          "type": "string",
          "enum": [
            "extraction",
            "scaling_and_root_planing",
            "biopsy"
          ]
        },
        "primary_closure": {
          "type": "boolean",
          "description": "Must be true for patients starting bisphosphonates to ensure healing."
        }
      },
      "required": [
        "tooth_number",
        "action",
        "primary_closure"
      ]
    },
    "example_output": {
      "outcome": "successful",
      "hemostasis": "achieved"
    }
  },
  "administer_medication": {
    "description": "Prescribes or administers supportive medications such as antibiotics or chlorhexidine.",
    "parameters": {
      "type": "object",
      "properties": {
        "medication_name": {
          "type": "string"
        },
        "indication": {
          "type": "string"
        }
      },
      "required": [
        "medication_name"
      ]
    },
    "example_output": {
      "status": "administered"
    }
  },
  "finalize_clearance": {
    "description": "Issues the formal dental clearance to the oncologist if all metrics are met.",
    "parameters": {
      "type": "object",
      "properties": {
        "final_assessment": {
          "type": "string"
        },
        "readiness_metric": {
          "type": "string",
          "description": "Clinical confirmation of site healing."
        }
      },
      "required": [
        "final_assessment",
        "readiness_metric"
      ]
    },
    "example_output": {
      "clearance_submitted": true
    }
  }
}
